// MakeShop 강사회원 중 파트너클래스 미등록자 필터링
var mkData = $('MakeShop 강사회원 조회').first().json;
var ncData = $('NocoDB 파트너 목록 조회').first().json;

// MakeShop 회원 목록 파싱
var mkList = mkData.list || [];
if (!Array.isArray(mkList)) {
  mkList = Object.values(mkList);
}

// NocoDB 파트너 목록 파싱 - 자사몰 ID로 Set 구성
var ncList = ncData.list || [];
if (!Array.isArray(ncList)) {
  ncList = Object.values(ncList);
}
var partnerIdSet = new Set();
for (var i = 0; i < ncList.length; i++) {
  var pid = (ncList[i]['자사몰 ID'] || '').trim().toLowerCase();
  if (pid) partnerIdSet.add(pid);
}

// 미등록 강사 필터
var results = [];
var skippedNoEmail = 0;
var skippedNoReceive = 0;
var skippedAlreadyPartner = 0;

for (var j = 0; j < mkList.length; j++) {
  var member = mkList[j];
  var loginId = (member.login || member.id || '').trim().toLowerCase();

  // 이미 파트너클래스 등록된 회원 제외
  if (partnerIdSet.has(loginId)) {
    skippedAlreadyPartner++;
    continue;
  }

  // 이메일 필수 + 수신동의 체크
  var email = (member.email || '').trim();
  if (!email || email.indexOf('@') === -1) {
    skippedNoEmail++;
    continue;
  }

  var emailReceive = (member.email_receive || member.emailReceive || 'N').toUpperCase();
  if (emailReceive !== 'Y') {
    skippedNoReceive++;
    continue;
  }

  var name = member.hname || member.name || '선생님';
  var phone = (member.mobile || member.phone || '').replace(/[^0-9]/g, '').replace(/^82/, '0');

  results.push({
    json: {
      loginId: loginId,
      name: name,
      email: email,
      phone: phone,
      hasPhone: phone.length >= 10,
      grade: member.grade || ''
    }
  });

  // 초기 100명 제한
  if (results.length >= 100) break;
}

if (results.length === 0) {
  return [{
    json: {
      empty: true,
      totalMakeshop: mkList.length,
      totalPartner: ncList.length,
      skippedAlreadyPartner: skippedAlreadyPartner,
      skippedNoEmail: skippedNoEmail,
      skippedNoReceive: skippedNoReceive
    }
  }];
}

// 첫 번째 아이템에 통계 추가
results[0].json.stats = {
  totalMakeshop: mkList.length,
  totalPartner: ncList.length,
  skippedAlreadyPartner: skippedAlreadyPartner,
  skippedNoEmail: skippedNoEmail,
  skippedNoReceive: skippedNoReceive,
  targetCount: results.length
};

return results;

// 이메일 발송 결과 확인
var item = $input.item.json || {};
var prev = $('대상 있는가').item.json || {};
var errorMsg = '';

if (typeof item.error === 'string' && item.error) {
  errorMsg = item.error;
} else if (Array.isArray(item.rejected) && item.rejected.length > 0) {
  errorMsg = 'Rejected: ' + item.rejected.join(', ');
}

var emailOk = errorMsg === '';

return {
  json: {
    loginId: prev.loginId || '',
    name: prev.name || '',
    email: prev.email || '',
    phone: prev.phone || '',
    hasPhone: prev.hasPhone || false,
    emailSuccess: emailOk,
    emailError: errorMsg,
    stats: prev.stats || null
  }
};

