// 전체 발송 결과 집계
var emailItems = $('이메일 결과 확인').all();
var smsItems = $input.all();

var emailOk = 0;
var emailFail = 0;
var smsOk = 0;
var smsFail = 0;
var smsSkipped = 0;
var stats = null;

for (var i = 0; i < emailItems.length; i++) {
  var e = emailItems[i].json;
  if (e.emailSuccess) emailOk++;
  else emailFail++;
  if (!stats && e.stats) stats = e.stats;
}

for (var j = 0; j < smsItems.length; j++) {
  var s = smsItems[j].json;
  // 알리고 응답: result_code가 1이면 성공
  if (s.result_code === 1 || s.result_code === '1') smsOk++;
  else if (s.hasPhone === false || s.empty) smsSkipped++;
  else smsFail++;
}

var now = new Date();
var kst = new Date(now.getTime() + 9 * 60 * 60 * 1000);
var timeStr = kst.toISOString().replace('T', ' ').substring(0, 19) + ' KST';

var msg = '<b>PARTNER-ONBOARD 캠페인 결과</b>\n\n';

if (stats) {
  msg += 'MakeShop 강사회원: ' + stats.totalMakeshop + '명\n';
  msg += 'NocoDB 파트너 등록: ' + stats.totalPartner + '명\n';
  msg += '이미 파트너: ' + stats.skippedAlreadyPartner + '명\n';
  msg += '이메일 없음: ' + stats.skippedNoEmail + '명\n';
  msg += '수신거부: ' + stats.skippedNoReceive + '명\n';
  msg += '발송 대상: ' + stats.targetCount + '명\n\n';
}

msg += '이메일: ' + emailOk + '건 성공';
if (emailFail > 0) msg += ', ' + emailFail + '건 실패';
msg += '\n';

msg += 'SMS: ' + smsOk + '건 성공';
if (smsFail > 0) msg += ', ' + smsFail + '건 실패';
if (smsSkipped > 0) msg += ', ' + smsSkipped + '건 스킵';
msg += ' (테스트모드)\n\n';

msg += timeStr;

return [{ json: { message: msg } }];

// 대상 없음 - 텔레그램 메시지 생성
var data = $input.first().json;

var now = new Date();
var kst = new Date(now.getTime() + 9 * 60 * 60 * 1000);
var timeStr = kst.toISOString().replace('T', ' ').substring(0, 19) + ' KST';

var msg = '<b>PARTNER-ONBOARD 캠페인</b>\n\n';
msg += '미등록 강사 없음\n\n';
if (data.totalMakeshop !== undefined) {
  msg += 'MakeShop 강사회원: ' + data.totalMakeshop + '명\n';
  msg += 'NocoDB 파트너 등록: ' + data.totalPartner + '명\n';
  msg += '이미 파트너: ' + data.skippedAlreadyPartner + '명\n';
  msg += '이메일 없음: ' + data.skippedNoEmail + '명\n';
  msg += '수신거부: ' + data.skippedNoReceive + '명\n';
}
msg += '\n' + timeStr;

return [{ json: { message: msg } }];
